esqlQuery.esql:
FROM metrics-redisenterprise.otel-default
| WHERE node_free_memory IS NOT NULL
| STATS avg_free = AVG(node_free_memory) BY node, cluster
| EVAL free_gb = ROUND(avg_free / 1073741824, 2)
// Alert when free memory drops below 1 GB
// Low node memory can cause OOM kills, swap thrashing, and fork failures
// Adjust threshold based on your node's total RAM and provisioning model
// Nodes with overbooking enabled may legitimately run with lower free memory
| WHERE free_gb < 1
| SORT free_gb ASC
